import numpy as np
import math

def pos_encoding(position: int, d_model: int):
    if position == 0 or d_model <= 0:
        return -1

    pe = [[0.0] * d_model for _ in range(position)]

    for pos in range(position):
        for i in range(0, d_model, 2):
            denom = math.pow(10000, (2 * i) / d_model)
            pe[pos][i] = math.sin(pos / denom)
            if i + 1 < d_model:
                pe[pos][i + 1] = math.cos(pos / denom)

    pos_encoding = np.array(pe, dtype=np.float16)
    return pos_encoding
